function checkTrack(s,d,v){var z=s.y==d.y?0:1;var r=true;if(z==0){var x=s.x<d.x?s.x:d.x;var y=s.x<d.x?d.x:s.x;for(var k=x;k<=y;k++){if(g.data.dGrid[s.y][k][4]!=null&&g.data.dGrid[s.y][k][4]!=v){r=false;break;}}}
if(z==1){var x=s.y<d.y?s.y:d.y;var y=s.y<d.y?d.y:s.y;for(var k=x;k<=y;k++){if(g.data.dGrid[k][s.x][4]!=null&&g.data.dGrid[k][s.x][4]!=v){r=false;break;}}}
return r;}
function updateTime(){g.data.clock.min=g.data.clock.min+1;var d=false;if(g.data.clock.min==60){g.data.clock.h++;if(g.data.clock.h==24){g.data.clock.d++;if(g.data.clock.y%4>0&&g.data.clock.m==1&&g.data.clock.d==28){g.data.clock.m++;g.data.clock.d=0;}
if(g.data.clock.y%4==0&&g.data.clock.m==1&&g.data.clock.d==29){g.data.clock.m++;g.data.clock.d=0;}
if((g.data.clock.m==0||g.data.clock.m==2||g.data.clock.m==4||g.data.clock.m==6||g.data.clock.m==7||g.data.clock.m==9||g.data.clock.m==11)&&g.data.clock.d==31){g.data.clock.m++;g.data.clock.d=0;}
if((g.data.clock.m==3||g.data.clock.m==5||g.data.clock.m==8||g.data.clock.m==10)&&g.data.clock.d==30){g.data.clock.m++;g.data.clock.d=0;}
if(g.data.clock.m==12){g.data.clock.y++;g.data.clock.m=0;}
g.data.clock.h=0;d=true;}
g.data.clock.min=0;}
formatTimeText();if(d)postDayActions();}
function postDayActions(){openToast("At the end of "+$("#gClock").text().trim()+":<br>"+g.data.TOTPAXM+" out of "+g.data.TOTPAXW+" PAX were moved.<br>Operational Efficiency :"+(g.data.TOTPAXM*100/g.data.TOTPAXW).toFixed(2)+"%",true);}
function formatTimeText(){$("#gClock").text(g.data.clock.y+"Y "+("0"+g.data.clock.m).slice(-2)+"M "+("0"+g.data.clock.d).slice(-2)+"D "+("0"+g.data.clock.h).slice(-2)+"H "+("0"+g.data.clock.min).slice(-2)+"m ");}
function toggleAnimation(btn){const icon=$(btn).children().first();if($(icon).hasClass("fa-play")){$(icon).removeClass("fa-play").addClass("fa-pause");g.animID=setInterval(startAnimation,g.params.animLoopInt);}else{$(icon).removeClass("fa-pause").addClass("fa-play");clearInterval(g.animID);g.anim=0;}}
function toggleBuildMode(btn){const icon=$(btn).children().first();if($(icon).hasClass("fa-screwdriver-wrench")){$(icon).removeClass("fa-screwdriver-wrench").addClass("fa-spinner fa-spin-pulse");$(".bottomrightbuttons").hide();$(".topleftbuttons").hide();hideInfoBox();hideHelpBox();clearInterval(g.animID);g.build=1;g.lp=[];}else{$(icon).removeClass("fa-spinner fa-spin-pulse").addClass("fa-screwdriver-wrench");g.build=0;$(".toastify-top").remove();g.net=new Network();addJN();addLN();detectConn();updateBoxInfo();$(".bottomrightbuttons").show();$(".topleftbuttons").show();g.lp=[];if(g.anim)g.animID=setInterval(startAnimation,g.params.animLoopInt);}}
function addJN(){for(var v=0;v<g.data.dGrid.length;v++){for(var h=0;h<g.data.dGrid[v].length;h++){if(g.data.dGrid[v][h]){if(g.data.dGrid[v][h][3]==5){g.net.addVertex(v*g.params.gridBox+h);}}}}}
function addLN(){for(var v=0;v<g.data.dGrid.length;v++){for(var h=0;h<g.data.dGrid[v].length;h++){if(g.data.dGrid[v][h]&&g.data.dGrid[v][h][3]==5){var nHJN=getNextHJN(v,h);var nVJN=getNextVJN(v,h);if(nHJN[0]){var c=true;var d=true;var t=0;if(nHJN[1]-h==1){d=false;}else{for(var i=h+1;i<nHJN[1];i++){if(g.data.dGrid[v][h+1])t=g.data.dGrid[v][h+1][3];if(!g.data.dGrid[v][i]||g.data.dGrid[v][i][3]!=t){c=false;break;}}}
if(c){if(t==1||t==0)g.net.addEdge(v*g.params.gridBox+h,v*g.params.gridBox+nHJN[1],d);if(t==2)g.net.addEdge(v*g.params.gridBox+nHJN[1],v*g.params.gridBox+h,d);}}
if(nVJN[0]){var c=true;var d=true;var t=0;if(nVJN[1]-v==1){d=false;}else{for(var i=v+1;i<nVJN[1];i++){if(g.data.dGrid[v+1][h])t=g.data.dGrid[v+1][h][3];if(!g.data.dGrid[i][h]||g.data.dGrid[i][h][3]!=t){c=false;break;}}}
if(c){if(t==3||t==0)g.net.addEdge(v*g.params.gridBox+h,nVJN[1]*g.params.gridBox+h,d);if(t==4)g.net.addEdge(nVJN[1]*g.params.gridBox+h,v*g.params.gridBox+h,d);}}}}}}
function getNextHJN(v,h){var n=[false,];var r=h+1;for(r;r<g.data.dGrid[v].length;r++){if(g.data.dGrid[v][r]&&g.data.dGrid[v][r][3]==5){n=[true,r];break;}}
return n;}
function getNextVJN(v,h){var n=[false,];var r=v+1;for(r;r<g.data.dGrid.length;r++){if(g.data.dGrid[r][h]&&g.data.dGrid[r][h][3]==5){n=[true,r];break;}}
return n;}
class Network{constructor(){this.adjacencyList=new Map();this.allPaths=[];this.currentPath=[];this.queue=[];}
addVertex(vertex){if(!this.adjacencyList.has(vertex)){this.adjacencyList.set(vertex,[]);}}
addEdge(vertex1,vertex2,directed){if(this.adjacencyList.has(vertex1)&&this.adjacencyList.has(vertex2)){this.adjacencyList.get(vertex1).push(vertex2);if(!directed)this.adjacencyList.get(vertex2).push(vertex1);}else{console.error("One or both vertices not found.");}}
removeEdge(vertex1,vertex2){if(this.adjacencyList.has(vertex1)&&this.adjacencyList.has(vertex2)){this.adjacencyList.set(vertex1,this.adjacencyList.get(vertex1).filter(v=>v!==vertex2));this.adjacencyList.set(vertex2,this.adjacencyList.get(vertex2).filter(v=>v!==vertex1));}}
removeVertex(vertex){if(this.adjacencyList.has(vertex)){for(var neighbor of this.adjacencyList.get(vertex)){this.removeEdge(vertex,neighbor);}
this.adjacencyList.delete(vertex);}}
printNetwork(){for(var[vertex,neighbors]of this.adjacencyList){console.log(`${vertex}:${neighbors.join(', ')}`);}}
findAllPathsBFS(vertex1,vertex2){this.allPaths=[];this.queue=[[vertex1]];while(this.queue.length>0){const currentPath=this.queue.shift();const currentNode=currentPath[currentPath.length-1];if(currentNode===vertex2){this.allPaths.push(currentPath);}else{const neighbors=this.adjacencyList.get(currentNode)||[];for(const neighbor of neighbors){if(!currentPath.includes(neighbor)){const newPath=[...currentPath,neighbor];this.queue.push(newPath);}}}}
return this.allPaths;}
findAllPathsDFS(vertex1,vertex2){this.allPaths=[];this.currentPath=[];this.dfs(vertex1,vertex2);return this.allPaths;}
dfs(currentNode,targetNode){this.currentPath.push(currentNode);if(currentNode===targetNode){this.allPaths.push([...this.currentPath]);}else{const neighbors=this.adjacencyList.get(currentNode);if(neighbors){for(const neighbor of neighbors){if(!this.currentPath.includes(neighbor)){this.dfs(neighbor,targetNode);}}}}
this.currentPath.pop();}}
function exportGame(){var f=g.data.gname;g.data.version=parseFloat((g.data.version+0.001).toFixed(3));clearInterval(g.animID);var exportLink=$('#exportLink');exportLink.attr("href","data:text/json;charset=utf-8,"+encodeURIComponent(JSON.stringify(g.data)));exportLink.attr("download",f+"_v"+g.data.version+".json");exportLink[0].click();exportLink.attr("href","");if(g.anim)g.animID=setInterval(startAnimation,g.params.animLoopInt);}
function processImport(){var file=$('#importFile')[0].files[0];var reader=new FileReader()
reader.fileName=file.name;reader.onload=function(e){toggleOverlay("block");importGame(JSON.parse(e.target.result),false);}
reader.readAsText(file,"UTF-8");$('#importFile').val("");}
function importGame(gD,c){if(c){if(confirm("Importing saved file will discard current game.\nDo you want to proceed with the import?")){clearInterval(g.animID);g.mousedown=null;importFile();}
return;}else{hideInfoBox();hideHelpBox();$(".toastify-bottom").remove();g.data=gD;g.net=new Network();addJN();addLN();detectConn();$('#gcanvas').css('background-color',g.params.ccolor[g.params.dark]);$(".playpause").removeClass("fa-play fs-pause");if(g.params.pause){$('#pauseOnImport').prop('checked',true);$(".playpause").addClass("fa-play");clearInterval(g.animID);g.anim=0;updateTime();resize();}
else{$(".playpause").addClass("fa-pause");g.animID=setInterval(startAnimation,g.params.animLoopInt);$('#pauseOnImport').prop('checked',false);}
toggleOverlay("none");openToast(g.data.gname+" game loaded.",false,1000);}}
function updateName(){if(!isAlphaNumeric($("#gridName").val())){openToast("Only alphaNumeric value allowed!",false,1000,"pink");$("#gridName").val(g.data.gname);return;}
g.data.gname=$("#gridName").val().toUpperCase();$("#gridName").val(g.data.gname);g.data.version=0;}
function setPause(o){g.params.pause=$(o).prop('checked');}
function setDark(o){g.params.dark=$(o).prop('checked');$('#gcanvas').css('background-color',g.params.ccolor[g.params.dark]);if(!g.anim)resize();}